from fastapi import APIRouter
from fastapi.responses import HTMLResponse

router = APIRouter(tags=["guided-provider-setup-frontend"])

HTML = """
<!doctype html><html lang="pt-PT"><head><meta charset="utf-8"/><meta name="viewport" content="width=device-width, initial-scale=1"/><title>Guided Provider Setup</title><style>:root{color-scheme:dark;--panel:#0f172a;--line:#26344f;--text:#eef5ff;--muted:#9fb0d0;--ok:#22c55e;--warn:#f59e0b;--bad:#ef4444}*{box-sizing:border-box}body{margin:0;font-family:Inter,Arial,sans-serif;background:radial-gradient(circle at top,#173766,#050816 55%);color:var(--text)}.page{padding:10px;display:grid;gap:10px}.panel,.card{background:rgba(15,23,42,.94);border:1px solid var(--line);border-radius:22px;padding:13px}h1,h2{margin:.1rem 0}.muted{color:var(--muted)}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(210px,1fr));gap:8px}.buttons{display:grid;grid-template-columns:repeat(auto-fit,minmax(145px,1fr));gap:8px}button,input,textarea,select{font:inherit;border-radius:16px;border:1px solid var(--line);background:#0b1220;color:var(--text);padding:12px}button{background:linear-gradient(135deg,#0284c7,#38bdf8);border:none;color:#02101b;font-weight:1000}button.dark{background:#0b1220;color:var(--text);border:1px solid var(--line)}.item{border-left:4px solid var(--ok);padding:9px 10px;background:#081226;border-radius:14px;word-break:break-word}.warn{border-left-color:var(--warn)}textarea{width:100%;min-height:90px}iframe{width:100%;height:520px;border:1px solid var(--line);border-radius:18px;background:#fff}pre{white-space:pre-wrap;overflow:auto;font-size:12px;max-height:520px;background:#081226;border:1px solid var(--line);border-radius:18px;padding:12px}@media(max-width:760px){.buttons{grid-template-columns:1fr}iframe{height:430px}}</style></head><body><div class="page"><section class="panel"><h1>Guided Provider Setup</h1><p class="muted">Modo Deus controlado: abre provider oficial, mostra popup limpo, guarda campos sensíveis no Vault e pede gate para preencher/avançar localmente.</p><div class="buttons"><button onclick="location.href='/app/install-use-now'" class="dark">Install & Use</button><button onclick="location.href='/app/connect-phone'" class="dark">Connect Phone</button><button onclick="dashboard()">Dashboard</button></div></section><section class="panel"><h2>Provider</h2><div class="grid"><select id="provider"><option value="tailscale">Tailscale</option><option value="cloudflare_tunnel">Cloudflare Tunnel</option><option value="ngrok">Ngrok</option><option value="manual_https">Manual HTTPS</option></select><input id="sessionId" placeholder="provider-setup-..."/></div><div class="buttons"><button onclick="startSetup()">Começar setup guiado</button><button onclick="openOfficial()" class="dark">Abrir página oficial</button></div></section><section class="panel"><h2>Popup limpo do God Mode</h2><p class="muted">Preenche aqui só o necessário. Campos sensíveis vão para o Vault local; o contrato pede aprovação no telemóvel antes de preencher/avançar no provider.</p><div class="grid"><input id="accountEmail" placeholder="email/conta"/><input id="accountSecret" type="password" placeholder="segredo da conta, opcional"/><input id="mfaCode" placeholder="código MFA se aparecer, opcional"/></div><div class="buttons"><button onclick="browserAssist()">Criar contrato browser assist</button></div></section><section class="panel"><h2>O que o God Mode vai fazer</h2><div id="steps" class="grid"></div></section><section class="panel"><h2>Capturar resultado final</h2><div class="grid"><input id="pcTail" placeholder="PC Tailscale IP ou MagicDNS"/><input id="publicUrl" placeholder="https://url-remota-final"/><input id="label" placeholder="label/tailnet/tunnel"/></div><div class="buttons"><button onclick="capture()">Guardar resultado remoto</button></div></section><section class="panel"><h2>Página oficial</h2><p class="muted">Alguns providers bloqueiam iframe; se não aparecer, usa “Abrir página oficial”.</p><iframe id="frame"></iframe></section><section class="panel"><h2>Resultado</h2><pre id="out"></pre></section></div><script>const qs=s=>document.querySelector(s);let current=null;async function api(p,o){const r=await fetch(p,o);const t=await r.text();let j;try{j=JSON.parse(t)}catch{j={raw:t}};if(!r.ok)throw new Error(t);return j}function esc(s){return String(s??'').replaceAll('<','&lt;')}function show(x){qs('#out').textContent=JSON.stringify(x,null,2);render(x)}function render(x){if(x?.setup_session){current=x.setup_session;qs('#sessionId').value=current.setup_session_id;qs('#frame').src=current.official_url||'about:blank';qs('#steps').innerHTML=(current.safe_steps||[]).map((s,i)=>`<div class="item"><b>${i+1}</b><br>${esc(s)}</div>`).join('')} const sessions=x?.setup_sessions||[]; if(!current&&sessions.length){current=sessions[sessions.length-1];qs('#sessionId').value=current.setup_session_id}}async function startSetup(){show(await api('/api/guided-provider-setup/start',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({provider:qs('#provider').value})}))}function openOfficial(){if(current?.official_url) window.open(current.official_url,'_blank');}async function browserAssist(){const form_values={account_email:qs('#accountEmail').value,account_secret:qs('#accountSecret').value,mfa_code:qs('#mfaCode').value};show(await api('/api/guided-provider-setup/browser-assist-contract',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({setup_session_id:qs('#sessionId').value,form_values,operation:'signup_or_login'})}))}async function capture(){const values={pc_tailscale_ip_or_magicdns:qs('#pcTail').value,public_https_url:qs('#publicUrl').value,label:qs('#label').value};show(await api('/api/guided-provider-setup/capture-result',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({setup_session_id:qs('#sessionId').value,values,store_remote_profile:true,store_sensitive_material_in_vault:false})}))}async function dashboard(){show(await api('/api/guided-provider-setup/dashboard'))}dashboard()</script></body></html>
"""


@router.get('/app/guided-provider-setup', response_class=HTMLResponse)
async def guided_provider_setup_frontend() -> HTMLResponse:
    return HTMLResponse(content=HTML)


@router.get('/app/setup-remote-access', response_class=HTMLResponse)
async def setup_remote_access_alias() -> HTMLResponse:
    return HTMLResponse(content=HTML)
